-- ============================================================
-- EPISODES (2 per anime = 200 episodes)
-- ============================================================
INSERT INTO episodes (anime_id, slug, title, eps_number, uploaded_at)
SELECT
  a.id,
  a.slug || '-episode-' || n,
  a.title || ' Episode ' || n,
  n,
  date('now', '-' || (20 - n) || ' days')
FROM anime a
CROSS JOIN (SELECT 1 AS n UNION SELECT 2) n;
